# retry.py
import time
import math
from typing import Callable, Type, Tuple

def retry_call(
    fn: Callable[[], T],
    max_attempts: int = 5,
    base_delay: float = 1.0,
    exceptions: Tuple[Type[Exception], ...] = (Exception,),
) -> T:
    """Retry fn with exponential backoff.

    Delays: base_delay * 2**attempt, capped at max_attempts.
    """
    for attempt in range(max_attempts):
        try:
            return fn()
        except exceptions:
            if attempt == max_attempts - 1:
                raise
            time.sleep(base_delay * 2**attempt)
    raise RuntimeError("retry exhausted")  # unreachable, keeps type checker happy
```

Rationale: minimal surface, no external deps; exponential delay reduces server load after failures; configurable exceptions and attempts keep it reusable for network errors only.

